UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('4f5731d6-a000-4036-a630-5b72665bfa3a'::uuid, 'La sécheresse cutanée exacerbe les démangeaisons, cette crème émolliente restaure la barrière hydrique de la peau pour la calmer.'),('803da6d3-1809-49ee-87ac-3519dd2ea90f'::uuid, 'L''histamine est un puissant médiateur de prurit, un antihistaminique oral bloque ses récepteurs pour réduire les démangeaisons.'),('c5fe0012-2cf2-4b5e-b3cf-4a5cbf49e0e7'::uuid, 'Le psoriasis se caractérise par une accumulation excessive de cellules cutanées, cette crème à l''urée ramollit et détache les squames.'),('ce9fafbd-854d-4140-8bc6-c93455f4ea1e'::uuid, 'La peau psoriasique présente un épaississement et une desquamation, l''émollient kératolytique favorise l''élimination des cellules mortes et hydrate.'),('2f614c84-dae4-45d9-8d8a-91074686ceab'::uuid, 'Le psoriasis du cuir chevelu provoque une forte desquamation, le shampoing kératolytique dissout les squames pour assainir le cuir chevelu.'),('e080a29c-369a-4fd6-8eaf-fd8d2fe79cf6'::uuid, 'La rectocolite hémorragique est associée à un déséquilibre du microbiote, les probiotiques contribuent à restaurer une flore intestinale saine.'),('0643b3c2-f439-47f3-b5d1-7423de24cb3c'::uuid, 'La rectocolite hémorragique altère la flore intestinale, les probiotiques VSL#3 aident à moduler la réponse immunitaire locale.'),('5fc90b10-73ac-4c59-b141-0a8c385a23ad'::uuid, 'Le reflux gastrique consiste en la remontée d''acidité, l''alginate forme une barrière physique qui protège l''œsophage des brûlures.'),('2cfcfa69-0c05-4e29-ae77-07bf78e5cc15'::uuid, 'L''acide gastrique irrite l''œsophage lors du reflux, le pansement gastrique tapisse la muqueuse pour la protéger des agressions.'),('87098a68-393f-4443-991e-f640b1230c8e'::uuid, 'Le reflux est dû à une acidité gastrique excessive, l''antiacide neutralise rapidement cette acidité pour un soulagement immédiat des brûlures.'),('dd7e21a2-2207-4b04-9536-970f405941fb'::uuid, 'Le reflux gastro-œsophagien peut déséquilibrer la flore digestive, ces probiotiques aident à maintenir l''équilibre du microbiote intestinal.'),('2957f672-8508-41bc-8caa-e42ddc281759'::uuid, 'Le reflux gastro-œsophagien peut perturber l''écosystème digestif, ces probiotiques soutiennent l''intégrité de la flore intestinale.'),('0752ed27-a61c-4e71-9a9c-c6e9d520f3b1'::uuid, 'Le reflux acide influence l''environnement digestif, ces probiotiques contribuent à l''équilibre de la flore microbienne du système gastro-intestinal.'),('1e09c1d4-ecc7-417d-9c06-bf58a746c71c'::uuid, 'Le reflux est causé par l''acidité gastrique, cet antiacide neutralise rapidement le pH pour soulager les brûlures.'),('86183139-2703-4cb5-b6b1-de1104a12bc1'::uuid, 'Le reflux irrite l''œsophage, l''alginate forme un radeau protecteur sur le liquide gastrique pour prévenir les régurgitations acides.'),('0b258148-35e8-4e42-9f67-244b731bc82d'::uuid, 'Un déséquilibre du microbiote peut influencer la digestion, les probiotiques rééquilibrent la flore intestinale pour améliorer le transit.'),('8ceb9b56-61d4-479f-ae0e-2ac07875b8fc'::uuid, 'Le reflux peut affecter l''équilibre digestif, ces probiotiques contribuent à une flore intestinale stable pour une meilleure digestion.'),('fcb81666-7fa1-4bf4-b84f-6889515909fc'::uuid, 'Le reflux est lié à l''acide gastrique, cet antiacide agit en neutralisant rapidement l''acidité pour un soulagement immédiat.'),('20608089-695b-49b8-953a-233f6bb4289c'::uuid, 'Les perturbations digestives peuvent déséquilibrer la flore, ces probiotiques aident à protéger le microbiote pour soutenir la digestion.'),('05ad97e3-7a65-4c28-8e02-dcbc7ee28018'::uuid, 'Les règles douloureuses sont causées par l''inflammation, l''ibuprofène réduit cette inflammation pour atténuer efficacement la douleur.'),('be76d6a1-737f-4a29-934b-13b83627e25e'::uuid, 'Les règles provoquent des contractions utérines, la bouillotte applique une chaleur douce pour détendre les muscles spasmodiques.'),('bb3801e7-6f47-4d88-885c-dd3ae0ca4d13'::uuid, 'Les crampes menstruelles sont dues à une tension musculaire, ce patch diffuse une chaleur continue pour relâcher les muscles utérins.'),('5ebdcfc3-4aa7-4f70-adb7-395651e20e83'::uuid, 'La rétention d''eau est liée à l''accumulation de liquides, la queue de cerise favorise l''élimination rénale pour réduire les œdèmes.'),('ad9fe0b9-22e6-4bca-ad56-f3f56464599e'::uuid, 'L''excès de liquides interstitiels cause la rétention d''eau, la queue de cerise stimule la diurèse pour alléger les tissus.'),('bd67a9cd-a613-483d-9d00-2ae9fb49e299'::uuid, 'La rétention d''eau est due à un déséquilibre hydrique, la piloselle agit comme un diurétique pour favoriser l''élimination rénale.'),('d3233f9d-6b53-4971-ba3a-770f38b87ee0'::uuid, 'La rétention hydrique peut signaler un déséquilibre, les Oméga 3 maintiennent la fonction vasculaire pour une meilleure régulation.'),('ae14a727-5d10-4ece-b30d-0c536d63ad9b'::uuid, 'Un déséquilibre vasculaire peut influencer la rétention hydrique, les Oméga 3 supportent la fonction cardiaque pour une meilleure circulation.'),('81c561b1-b0d8-4647-a6d6-1d613b8de5a9'::uuid, 'La rétention hydrique peut être liée à une dysfonction vasculaire, les Oméga 3 contribuent à la santé cardiovasculaire pour un bon équilibre des fluides.'),('0b4ee604-9847-4066-803e-1bb96e0a7b8b'::uuid, 'La rhinite aiguë peut affaiblir l''immunité, la vitamine D3 renforce les défenses naturelles pour mieux lutter contre l''infection.'),('79342c19-f260-4d05-9e07-494112ef2e16'::uuid, 'La rhinite entraîne un encombrement nasal, l''eau de mer isotonique nettoie les fosses nasales pour faciliter la respiration.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;